import{_ as s,n as a,p as i,Y as e}from"./chunks/framework.KP8KjELV.js";const E=JSON.parse('{"title":"空格","description":"","frontmatter":{},"headers":[],"relativePath":"Stack/CSS/Tutorial/text/white-space.md","filePath":"Stack/CSS/Tutorial/text/white-space.md","lastUpdated":1703840066000}'),t={name:"Stack/CSS/Tutorial/text/white-space.md"},p=e(`<h1 id="空格" tabindex="-1">空格 <a class="header-anchor" href="#空格" aria-label="Permalink to &quot;空格&quot;">​</a></h1><h2 id="一、基本规则" tabindex="-1">一、基本规则 <a class="header-anchor" href="#一、基本规则" aria-label="Permalink to &quot;一、基本规则&quot;">​</a></h2><p>HTML 代码的空格通常会被浏览器忽略。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073106.jpg" alt=""></p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;◡◡hello◡◡world◡◡&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>上面是一行 HTML 代码，文字的前部、内部和后部各有两个空格。为了便于识别，这里使用半圆形符号<code>◡</code>表示空格。</p><p>浏览器的输出结果如下。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hello world</span></span></code></pre></div><p>可以看到，文字的前部和后部的空格都会忽略，内部的连续空格只会算作一个。这就是浏览器处理空格的基本规则。</p><p>如果希望空格原样输出，可以使用<code>&lt;pre&gt;</code>标签。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pre</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;◡◡hello◡◡world◡◡&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pre</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>另一种方法是，改用 HTML 实体<code>&amp;nbsp;</code>表示空格。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&amp;nbsp;&amp;nbsp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hello</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&amp;nbsp;&amp;nbsp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">world</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&amp;nbsp;&amp;nbsp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="二、空格字符" tabindex="-1">二、空格字符 <a class="header-anchor" href="#二、空格字符" aria-label="Permalink to &quot;二、空格字符&quot;">​</a></h2><p>HTML 处理空格的规则，适用于多种字符。除了普通的空格键，还包括制表符（<code>\\t</code>）和换行符（<code>\\r</code>和<code>\\n</code>）。</p><p>浏览器会自动把这些符号转成普通的空格键。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;hello</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">world&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>上面代码中，文本内部包含了一个换行符，浏览器视同为空格，输出结果如下。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hello world</span></span></code></pre></div><p>所以，文本内部的换行是无效的（除非文本放在<code>&lt;pre&gt;</code>标签内）。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;hello&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">br</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;world&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>上面代码使用<code>&lt;br&gt;</code>标签显式表示换行。</p><h2 id="三、css-的-white-space-属性" tabindex="-1">三、CSS 的 white-space 属性 <a class="header-anchor" href="#三、css-的-white-space-属性" aria-label="Permalink to &quot;三、CSS 的 white-space 属性&quot;">​</a></h2><p>HTML 语言的空格处理，基本上就是直接过滤。这样的处理过于粗糙，完全忽视了原始文本内部的空格可能是有意义的。</p><p>CSS 提供了一个 white-space 属性，可以提供更精确一点的空格处理方式。该属性共有六个值，除了一个通用的<code>inherit</code>（继承父元素），下面依次介绍剩下的五个值。</p><h3 id="_3-1-white-space-normal" tabindex="-1">3.1 white-space: normal <a class="header-anchor" href="#_3-1-white-space-normal" aria-label="Permalink to &quot;3.1 white-space: normal&quot;">​</a></h3><p><code>white-space</code>属性的默认值为<code>normal</code>，表示浏览器以正常方式处理空格。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;◡◡hellohellohello◡hello</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">world</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>上面代码中，文本前部有两个空格，内部有一个长单词和一个换行符。</p><p>然后，容器<code>&lt;p&gt;</code>指定一个比较小的宽度。为了便于识别，背景色设为红色。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  background</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>显示效果如下图。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073101.png" alt=""></p><p>可以看到，文首的空格被忽略。由于容器太窄，第一个单词溢出容器，然后在后面一个空格处换行。文本内部的换行符自动转成了空格。</p><h3 id="_3-2-white-space-nowrap" tabindex="-1">3.2 white-space: nowrap <a class="header-anchor" href="#_3-2-white-space-nowrap" aria-label="Permalink to &quot;3.2 white-space: nowrap&quot;">​</a></h3><p><code>white-space</code>属性为<code>nowrap</code>时，不会因为超出容器宽度而发生换行。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  white-space</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">nowrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>显示效果如下图。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073102.png" alt=""></p><p>所有文本显示为一行，不会换行。</p><h3 id="_3-3-white-space-pre" tabindex="-1">3.3 white-space: pre <a class="header-anchor" href="#_3-3-white-space-pre" aria-label="Permalink to &quot;3.3 white-space: pre&quot;">​</a></h3><p><code>white-space</code>属性为<code>pre</code>时，就按照<code>&lt;pre&gt;</code>标签的方式处理。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  white-space</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pre</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>显示效果如下图。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073103.png" alt=""></p><p>上面结果与原始文本完全一致，所有空格和换行符都保留了。</p><h3 id="_3-4-white-space-pre-wrap" tabindex="-1">3.4 white-space: pre-wrap <a class="header-anchor" href="#_3-4-white-space-pre-wrap" aria-label="Permalink to &quot;3.4 white-space: pre-wrap&quot;">​</a></h3><p><code>white-space</code>属性为<code>pre-wrap</code>时，基本还是按照<code>&lt;pre&gt;</code>标签的方式处理，唯一区别是超出容器宽度时，会发生换行。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  white-space</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pre-wrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>显示效果如下图。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073104.png" alt=""></p><p>文首的空格、内部的空格和换行符都保留了，超出容器的地方发生了折行。</p><h3 id="_3-5-white-space-pre-line" tabindex="-1">3.5 white-space: pre-line <a class="header-anchor" href="#_3-5-white-space-pre-line" aria-label="Permalink to &quot;3.5 white-space: pre-line&quot;">​</a></h3><p><code>white-space</code>属性为<code>pre-line</code>时，意为保留换行符。除了换行符会原样输出，其他都与<code>white-space:normal</code>规则一致。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  white-space</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pre-line</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>显示效果如下图。</p><p><img src="https://www.wangbase.com/blogimg/asset/201807/bg2018073105.png" alt=""></p><p>除了文本内部的换行符没有转成空格，其他都与<code>normal</code>的处理规则一致。这对于诗歌类型的文本很有用。</p><h2 id="四、参考链接" tabindex="-1">四、参考链接 <a class="header-anchor" href="#四、参考链接" aria-label="Permalink to &quot;四、参考链接&quot;">​</a></h2><ul><li><a href="https://medium.com/@patrickbrosset/when-does-white-space-matter-in-html-b90e8a7cdd33" target="_blank" rel="noreferrer">When does white space matter in HTML?</a>，by Patrick Brosset</li><li><a href="https://css-tricks.com/almanac/properties/w/whitespace/" target="_blank" rel="noreferrer">white-space</a>，by Sara Cope</li></ul>`,60),h=[p];function l(n,k,c,d,r,o){return a(),i("div",null,h)}const y=s(t,[["render",l]]);export{E as __pageData,y as default};
